import anthropic
from pydantic import BaseModel

client = anthropic.Anthropic()

def pydantic_to_tool(
    name: str,
    description: str,
    input_model: type[BaseModel],
) -> dict:
    schema = input_model.model_json_schema()
    # Remove the top-level $defs (Pydantic internal references) if present
    schema.pop("$defs", None)
    return {
        "name": name,
        "description": description,
        "input_schema": schema,
    }

CREATE_TASK_TOOL = pydantic_to_tool(
    name="create_task",
    description="Create a new task in the project management system.",
    input_model=CreateTaskInput,
)

def run_task_creation_agent(user_request: str) -> CreateTaskInput:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[CREATE_TASK_TOOL],
        tool_choice={"type": "tool", "name": "create_task"},
        messages=[{"role": "user", "content": user_request}],
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "create_task":
            return CreateTaskInput(**block.input)
    raise ValueError("Model did not call create_task")

from typing import Union

class CreateTaskInputV1(BaseModel):
    title: str
    priority: Literal["low", "medium", "high"] = "medium"

class CreateTaskInputV2(CreateTaskInputV1):
    description: str = ""
    due_date: date | None = None
    tags: list[str] = []

def parse_task_input(raw: dict, version: int = 2) -> CreateTaskInputV2:
    if version == 1:
        v1 = CreateTaskInputV1(**raw)
        return CreateTaskInputV2(
            title=v1.title,
            priority=v1.priority,
        )
    return CreateTaskInputV2(**raw)

from typing import Type
from pydantic import BaseModel

ToolRegistry: dict[str, tuple[str, Type[BaseModel]]] = {}

def register_tool(name: str, description: str, model: Type[BaseModel]):
    ToolRegistry[name] = (description, model)

# Register tools
register_tool("create_task", "Create a new project task.", CreateTaskInput)
register_tool("search_docs", "Search the knowledge base.", SearchInput)

def get_tools_for_user(user_plan: str) -> list[dict]:
    allowed = {
        "free": ["search_docs"],
        "pro": ["search_docs", "create_task"],
    }.get(user_plan, [])

    return [
        {
            "name": name,
            "description": desc,
            "input_schema": model.model_json_schema(),
        }
        for name, (desc, model) in ToolRegistry.items()
        if name in allowed
    ]

class SearchInput(BaseModel):
    query: str = Field(..., min_length=1, max_length=500)
    max_results: int = Field(default=5, ge=1, le=20)
    filters: dict[str, str] = Field(default_factory=dict)

from pydantic import BaseModel, model_validator, Field
from datetime import date

class CreateTaskInput(BaseModel):
    title: str = Field(..., min_length=1, max_length=200)
    due_date: date | None = None
    priority: str = "medium"

    @model_validator(mode="after")
    def due_date_not_past(self) -> "CreateTaskInput":
        if self.due_date and self.due_date < date.today():
            raise ValueError(f"due_date {self.due_date} is in the past")
        return self

    @model_validator(mode="after")
    def critical_tasks_need_due_date(self) -> "CreateTaskInput":
        if self.priority == "critical" and not self.due_date:
            raise ValueError("Critical tasks must have a due_date")
        return self
